// src/pages/admin/AdminPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI } from '../../components/UI';
import { calcResolutionRate, avgResolutionTime } from '../../utils/helpers';
import LiveMap from '../../components/LiveMap';

export default function AdminPortal() {
  const { complaints } = useApp();
  const [activeTab, setActiveTab] = useState('DASHBOARD');

  const navItems = [
    { key: 'DASHBOARD', label: 'Nagpur Radar', icon: '📊', count: 0 },
    { key: 'REGISTRY', label: 'Station Database Ledger', icon: '🗃️', count: complaints.length }
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="HQ Command Deck" subtitle="Nagpur Railway Station Grid" 
        navItems={navItems} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'Admin Officer', role: 'Station Superintendent', initials: 'SS', avatarColor: '#B71C1C' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        {activeTab === 'DASHBOARD' ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16, flex: 1 }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14 }}>
              <KPI title="TOTAL STATION ALERTS" value={complaints.length} />
              <KPI title="RESOLUTION METRIC INDICES" value={`${calcResolutionRate(complaints)}%`} color="#2E7D32" />
              <KPI title="MEAN SWEEP LATENCY" value={`${avgResolutionTime(complaints)} Mins`} color="#4527A0" />
            </div>
            <div style={{ flex: 1 }}><LiveMap complaints={complaints} /></div>
          </div>
        ) : (
          <div style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 12, overflowY: 'auto', flex: 1 }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', fontSize: 13 }}>
              <thead>
                <tr style={{ background: '#F7F9FC', borderBottom: '1px solid #DDE3E9', color: '#546E7A' }}>
                  <th style={{ padding: 12 }}>TICKET ID</th>
                  <th style={{ padding: 12 }}>PLATFORM / REGION</th>
                  <th style={{ padding: 12 }}>WASTE MATERIAL</th>
                  <th style={{ padding: 12 }}>CONTEXT DETAILS</th>
                  <th style={{ padding: 12 }}>SNAPSHOT EVIDENCE</th>
                  <th style={{ padding: 12 }}>STATUS</th>
                </tr>
              </thead>
              <tbody>
                {complaints.map(c => (
                  <tr key={c.id} style={{ borderBottom: '1px solid #ECEFF1' }}>
                    <td style={{ padding: 12, fontFamily: 'monospace', fontWeight: 600 }}>{c.customTicketId}</td>
                    <td style={{ padding: 12, fontWeight: 700 }}>{c.area}</td>
                    <td style={{ padding: 12 }}>{c.emoji} {c.gtype}</td>
                    <td style={{ padding: 12 }}>{c.desc}</td>
                    <td style={{ padding: 12 }}>
                      {c.image ? <img src={c.image} alt="Evidence" style={{ width: 45, height: 45, borderRadius: 6, objectFit: 'cover' }} /> : <span style={{ color: '#90A4AE', fontSize: 11 }}>No Snap</span>}
                    </td>
                    <td style={{ padding: 12, fontWeight: 700, color: c.status === 'NEW' ? '#E65100' : '#2E7D32' }}>{c.status}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
